 66→function mmRow(label, value) {
 67→  return { label, value: formatMeasurement(value || 0) };
 68→}
 69→
 70→function areaRow(label, value) {
 71→  return { label, value: `${(Math.abs(value || 0) / 1_000_000).toFixed(2)} m²` };
 72→}
 73→
 74→function materialLabel(material) {
 75→  return material ? material.charAt(0).toUpperCase() + material.slice(1) : '—';
 76→}
 77→
 78→function trussShapeLabel(value) {
 79→  return String(value || '')
 80→    .split('_')
 81→    .map((part) => part ? part.charAt(0).toUpperCase() + part.slice(1) : '')
 82→    .join(' ') || '—';
 83→}
 84→
 85→function trussSupportLabel(floor, beamId) {
 86→  const beam = (floor?.beams || []).find((entry) => entry.id === beamId) || null;
 87→  if (!beam || !floor) return '—';
 88→  return getBeamDisplayLabel(beam, floor.columns || []);
 89→}
 90→
 91→function findObjectInFloor(floor, selectedType, selectedId) {
 92→  switch (selectedType) {
 93→    case 'wall':
 94→      return floor.walls?.find((wall) => wall.id === selectedId) || null;
 95→    case 'beam':
 96→      return (floor.beams || []).find((beam) => beam.id === selectedId) || null;
 97→    case 'column':
 98→      return (floor.columns || []).find((column) => column.id === selectedId) || null;
 99→    case 'slab':
100→      return (floor.slabs || []).find((slab) => slab.id === selectedId) || null;
101→    case 'stair':
102→      return (floor.stairs || []).find((stair) => stair.id === selectedId) || null;
103→    case 'landing':
104→      return (floor.landings || []).find((landing) => landing.id === selectedId) || null;
105→    case 'door':
106→      return floor.doors?.find((door) => door.id === selectedId) || null;
107→    case 'window':
108→      return floor.windows?.find((windowItem) => windowItem.id === selectedId) || null;
109→    case 'fixture':
110→      return (floor.fixtures || []).find((fixture) => fixture.id === selectedId) || null;
111→    case 'railing':
112→      return (floor.railings || []).find((r) => r.id === selectedId) || null;
113→    default:
114→      return null;
115→  }
116→}
117→
118→function findObjectInRoof(roofSystem, selectedType, selectedId) {
119→  if (!roofSystem) return null;
120→
121→  switch (selectedType) {
122→    case 'roofSystem':
123→      return roofSystem.id === selectedId ? roofSystem : null;
124→    case 'parapet':
125→      return (roofSystem.parapets || []).find((parapet) => parapet.id === selectedId) || null;
126→    case 'drain':
127→      return (roofSystem.drains || []).find((drain) => drain.id === selectedId) || null;
128→    case 'roofOpening':
129→      return (roofSystem.roofOpenings || []).find((opening) => opening.id === selectedId) || null;
130→    default:
131→      return null;
132→  }
133→}
134→
135→function findObjectInTrusses(project, selectedType, selectedId) {
136→  if (selectedType === 'trussSystem') {
137→    const trussSystem = (project?.trussSystems || []).find((entry) => entry.id === selectedId) || null;
138→    return trussSystem ? { trussSystem, trussInstance: null } : null;
139→  }
140→
141→  if (selectedType === 'trussInstance') {
142→    for (const trussSystem of project?.trussSystems || []) {
143→      const trussInstance = (trussSystem.trussInstances || []).find((entry) => entry.id === selectedId) || null;
144→      if (trussInstance) {
145→        return { trussSystem, trussInstance };
146→      }
147→    }
148→  }
149→
150→  return null;
151→}
152→
153→function titleForObject(selectedType, object, floor) {
154→  switch (selectedType) {
155→    case 'beam':
156→      return getBeamDisplayLabel(object, floor.columns || []);
157→    case 'column':
158→      return getColumnListLabel(object, floor.columns || []);
159→    case 'slab':
160→      return getSlabDisplayLabel(object);
161→    case 'stair':
162→      return getStairDisplayLabel(object);
163→    case 'landing':
164→      return getLandingDisplayLabel(object);
165→    case 'wall':
166→    case 'door':
167→    case 'window':
168→      return `${TYPE_LABELS[selectedType]} ${object.id.split('_').pop()}`;
169→    case 'fixture':
170→      return FIXTURE_TYPE_LABELS[object.fixtureType] || 'Fixture';
171→    case 'railing': {
172→      const typeLabel = object.type ? object.type.charAt(0).toUpperCase() + object.type.slice(1) : 'Railing';
173→      return `${typeLabel} Railing ${object.id.split('_').pop()}`;
174→    }
175→    case 'roofSystem':
176→      return object.name || 'Roof';
177→    case 'parapet':
178→      return object.name || `Parapet ${object.id.split('_').pop()}`;
179→    case 'drain':
180→      return object.name || `Drain ${object.id.split('_').pop()}`;
181→    case 'roofOpening':
182→      return object.name || `Roof Opening ${object.id.split('_').pop()}`;
183→    case 'trussSystem':
184→      return object.name || 'Truss System';
185→    case 'trussInstance': {
186→      const trussType = resolveTrussType(object.trussTypeId);
187→      return `${trussType.name} ${object.id.split('_').pop()}`;
188→    }
189→    default:
190→      return object?.id || TYPE_LABELS[selectedType] || 'Object';
191→  }
192→}
